import{c as o,Q as i,j as t,m as a}from"./chunks/framework.BI6u8GL6.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog.md","filePath":"guide/changelog.md","lastUpdated":1783157055000}'),r={name:"guide/changelog.md"};function l(d,e,n,c,s,u){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes are documented in this file. Format follows <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and versioning follows <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="_1-3-0-2026-07-04" tabindex="-1">[1.3.0] - 2026-07-04 <a class="header-anchor" href="#_1-3-0-2026-07-04" aria-label="Permalink to &quot;[1.3.0] - 2026-07-04&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>executeWithCallbacks</strong> — <code>MergeSpec.executeWithCallbacks(em)</code> flushes the persistence context to trigger JPA lifecycle callbacks before executing the native UPSERT</li><li><strong>Multi-row UPSERT batching</strong> — <code>MergeSpec.executeBatch()</code> automatically uses <code>INSERT INTO ... VALUES (...), (...) ON CONFLICT ...</code> multi-row syntax (MySQL/PostgreSQL), falls back to row-by-row when dialect doesn&#39;t support it</li><li><strong>supportsBatchUpsert()</strong> — <code>DialectStrategy</code> adds capability detection method; <code>MergeSpec</code> uses capability check instead of try-catch</li><li><strong>SoftDeleteBulkExecutor</strong> — Extracted bulk soft-delete operations from <code>SoftDeleteHelper</code> (~450 lines), Helper reduced to ~740 lines, all public APIs preserved via delegation for backward compatibility</li><li><strong>Lambda convenience overloads</strong> — <code>MyJpaRepository</code> and <code>MyJpaTemplate</code> add <code>Consumer&lt;QuerySpec&lt;T&gt;&gt;</code> Lambda overloads, no need for <code>new QuerySpec&lt;&gt;()</code><ul><li><code>findAll(consumer)</code>, <code>findOne(consumer)</code>, <code>count(consumer)</code>, <code>exists(consumer)</code></li><li><code>MyJpaTemplate</code> adds corresponding Lambda overloads</li></ul></li><li><strong>QuerySpec.of() factory method</strong> — <code>QuerySpec.of(consumer)</code> static factory reduces 3-line creation to 1 line</li><li><strong>Virtual thread compatibility</strong> — <code>SoftDeleteContext</code> and <code>DefaultMyJpaRepository</code> fully compatible with Java 21+ virtual threads <ul><li><code>withIgnore(Runnable)</code> and <code>withIgnore(Supplier)</code> convenience methods with automatic lifecycle management</li><li>Virtual thread isolation verification tests</li></ul></li><li><strong>UPSERT dialect expansion</strong> — <code>MergeSpec</code> supports 4 database dialects <ul><li><code>OracleDialect</code> (<code>MERGE INTO ... USING ... ON ... WHEN MATCHED/NOT MATCHED</code>)</li><li><code>SqlServerDialect</code> (<code>[bracket]</code> escaping + <code>MERGE INTO</code>)</li><li><code>DialectDetector</code> registers postgresql, mysql, oracle, sqlserver by default</li><li><code>removeDialect()</code> for runtime dialect removal</li></ul></li><li><strong>QueryAggregates</strong> — Standalone <code>count</code>/<code>sum</code>/<code>avg</code>/<code>max</code>/<code>min</code> aggregate expression factory methods</li><li><strong>softDeleteAll row protection</strong> — <code>SoftDeleteHelper.softDeleteAll()</code> adds <code>maxRows</code> parameter, defaults to 10000 rows max</li><li><strong>multiLike nested field validation</strong> — <code>multiLike(keyword, &quot;address.city&quot;)</code> now validates each segment via <code>IdentifierValidator.validateColumnName()</code></li><li><strong>EncryptConverter transaction cleanup</strong> — <code>registerTransactionCleanupIfNeeded()</code> auto-registers <code>afterCompletion</code> callback to clean Cipher ThreadLocal in virtual thread scenarios</li><li><strong>CacheAdapter SPI</strong> — Pluggable cache adapter interface for Redis/Caffeine/Hazelcast <ul><li><code>CacheAdapter</code> interface, <code>DisabledCacheAdapter</code> no-op implementation</li><li><code>QueryCacheManager</code> implements <code>CacheAdapter</code> (backward compatible)</li><li><code>MyJpaTemplate</code> uses <code>CacheAdapter</code> internally, adds <code>setCacheAdapter()</code>/<code>getCacheAdapter()</code></li><li><code>CacheInvalidationListener</code> accepts <code>CacheAdapter</code></li></ul></li><li><strong>Java module system compatibility</strong> — Complete <code>--add-opens</code> fix guide</li><li><strong>Op.resolve() strategy pattern</strong> — <code>Op</code> enum as single source of truth for predicate building</li></ul><h3 id="optimized" tabindex="-1">Optimized <a class="header-anchor" href="#optimized" aria-label="Permalink to &quot;Optimized&quot;">​</a></h3><ul><li><strong>EncryptionKeyManager LRU cache eviction</strong> — Key cache changed from FIFO to LRU strategy with access timestamp tracking</li><li><strong>SlowQueryDataSourceProxy lock removal</strong> — Removed <code>ReentrantLock</code>, uses <code>SampledEvictionCache.computeIfAbsent()</code> atomicity</li><li><strong>QuerySpec split</strong> — From 1265 lines to 887 lines + 7 helper classes</li><li><strong>Deprecated API cleanup</strong> — Removed 11 deprecated methods</li><li><strong>QuerySpec.copy() performance</strong> — Fast path for empty condition trees, skips deep copy</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>EncryptConverter Cipher pool leak</strong> — Cipher objects returned to pool on encryption/decryption failure paths</li><li><strong>BulkOperationTemplate iteration count</strong> — Fixed double-increment in failed batch iteration</li><li><strong>MergeSpec transaction management</strong> — Extracted <code>safeRollback()</code> to unify rollback logic</li><li><strong>QuerySpec.copy() deep copy</strong> — Fixed shallow copy causing shared mutable state in nested conditions</li><li><strong>NodeResolver LEFT JOIN soft-delete</strong> — Moved soft-delete condition from WHERE to ON clause</li><li><strong>EncryptConverter GCM state corruption</strong> — Removed ThreadLocal Cipher cache, create new instance per operation (JDK-8201324)</li><li><strong>CacheKeyBuilder recursion protection</strong> — 128-level depth limit prevents StackOverflowError</li><li>Plus 20+ additional bug fixes (see source CHANGELOG.md for full list)</li></ul><h2 id="_1-2-0-2026-06-12" tabindex="-1">[1.2.0] - 2026-06-12 <a class="header-anchor" href="#_1-2-0-2026-06-12" aria-label="Permalink to &quot;[1.2.0] - 2026-06-12&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>UPSERT/MERGE support</strong> — <code>MergeSpec</code> builder for PostgreSQL <code>ON CONFLICT</code>, MySQL <code>ON DUPLICATE KEY</code>, H2 <code>MERGE</code></li><li><strong>CTE support</strong> — <code>CteSpec</code> for non-recursive and recursive Common Table Expressions</li><li><strong>SQL slow query monitoring</strong> — <code>SqlSlowQueryInterceptor</code> + <code>myjpa-plus.monitoring</code> configuration</li><li><strong>Field encryption</strong> — <code>@Encrypt</code> annotation + <code>EncryptConverter</code> (AES/GCM, random IV)</li><li><strong>Field masking</strong> — <code>@Mask</code> annotation + <code>MaskSerializer</code> (Jackson, supports PHONE/EMAIL/ID_CARD/NAME)</li><li><strong>Optimistic lock retry</strong> — <code>@RetryOnOptimisticLock</code> annotation with exponential backoff</li><li><strong>Query result caching</strong> — <code>QueryCacheManager</code> with TTL expiration</li><li><strong>Database function calls</strong> — <code>func(field, functionName, comparisonOp, value)</code> condition method</li><li><strong>Case-insensitive string queries</strong> — <code>eqIgnoreCase</code>, <code>neIgnoreCase</code>, <code>likeIgnoreCase</code></li><li><strong>Multi-field LIKE search</strong> — <code>multiLike(keyword, &quot;field1&quot;, &quot;field2&quot;)</code> with string field names</li><li><strong>String soft delete</strong> — <code>@SoftDelete</code> supports String type deletedValue</li><li><strong>EntityManagerFactory support</strong> — Improved <code>EntityManagerFactory</code> integration</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Removed H2 database support</strong> — Tests unified on MySQL</li><li><strong>Removed BaseEntity class</strong> — Audit fields via <code>AuditEntityListener</code> without base class</li><li><strong>Refactored entity field extraction and dialect detection</strong></li><li><strong>Refactored bulk operation template</strong> — Optimized transaction management and memory control</li><li><strong>Refactored condition builder interfaces</strong> — Split into 8 sub-interfaces</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>not() semantics</strong> — Fixed negation condition group semantics</li><li><strong>Cache eviction</strong> — Fixed cache eviction in bulk operations</li><li><strong>LIKE wildcard escaping</strong> — Fixed <code>likeSafe()</code> wildcard escaping</li><li><strong>null validation</strong> — Unified condition method null validation</li></ul><h2 id="_1-1-0-2026-05-31" tabindex="-1">[1.1.0] - 2026-05-31 <a class="header-anchor" href="#_1-1-0-2026-05-31" aria-label="Permalink to &quot;[1.1.0] - 2026-05-31&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Enum conversion support</strong> — <code>@CodeEnum</code> + <code>@CodeEnumValue</code> annotations for Hibernate 6 enum mapping <ul><li>CHAR(1) storage for enum codes (e.g., &#39;0&#39;, &#39;1&#39;, &#39;M&#39;, &#39;F&#39;)</li><li>Supports int, long, String code fields</li><li>No converter class needed</li></ul></li><li><strong>multiLike string field names</strong> — <code>multiLike(keyword, &quot;field1&quot;, &quot;field2&quot;)</code> for dynamic field name scenarios</li><li><strong>Integer soft delete</strong> — <code>@SoftDelete(deletedIntValue = 1)</code> for integer-based delete markers</li><li><strong>MyJpaTemplate.count()</strong> — Convenience count method</li><li><strong>Aggregate functions API</strong> — New aggregate query functionality</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>ConditionBuilder</code> adds <code>notBetween</code> and <code>likeIgnoreCase</code> condition variants</li><li><code>SubQuerySpec</code> and <code>AbstractBulkOperationSpec</code> add more condition convenience methods</li><li>Optimized <code>LambdaUtils</code> cache eviction with CAS operations</li><li>Optimized <code>InClauseBuilder</code> batch processing</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>EXISTS subquery association limitation</li><li><code>MyJpaTemplate.findAllStream</code> deprecation strategy</li><li><code>DefaultMyJpaRepository.deleteById</code> for soft-deleted entities</li></ul><h2 id="_1-0-0-2026-05-28" tabindex="-1">[1.0.0] - 2026-05-28 <a class="header-anchor" href="#_1-0-0-2026-05-28" aria-label="Permalink to &quot;[1.0.0] - 2026-05-28&quot;">​</a></h2><h3 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h3><ul><li><code>DeleteSpec</code> now requires explicit WHERE conditions</li><li>Fixed <code>resolveOr()</code> empty group semantics</li></ul><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>eqIgnoreCase</code> / <code>likeIgnoreCase</code> — Case-insensitive string conditions</li><li><code>groupBy(SFunction...)</code> — GROUP BY clause support</li><li><code>having(BiFunction)</code> — HAVING clause for aggregate queries</li><li><code>not(Consumer)</code> — Negation condition groups</li><li><code>startsWith</code> / <code>endsWith</code> / <code>contains</code> — Convenience LIKE methods</li><li>Consumer pattern: <code>or(Consumer)</code> / <code>join(field, Consumer)</code> / <code>leftJoin(field, Consumer)</code></li><li>Spring Boot auto-configuration</li><li><code>ProjectionSpec</code> — DTO projection queries</li><li><code>MyJpaTemplate</code> streaming API and batch operations</li><li>Conditional (guarded) methods for all condition builders</li><li><code>EntityGraphHelper</code> — Dynamic JPA EntityGraph builder</li><li><code>PageableHelper</code> — QuerySpec/Pageable sort integration</li></ul><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>SubQuerySpec</code> conditions no longer override each other</li><li>Race condition in <code>SoftDeleteHelper.findSoftDeleteField()</code></li></ul><h2 id="_0-0-2-2026-05-28" tabindex="-1">[0.0.2] - 2026-05-28 <a class="header-anchor" href="#_0-0-2-2026-05-28" aria-label="Permalink to &quot;[0.0.2] - 2026-05-28&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Batch operation LIMIT support</strong> — <code>executeWithMaxRows()</code> for max affected rows</li><li><strong>Large IN clause handling</strong> — Auto-split IN clauses exceeding database parameter limits</li><li><strong>GroupBy + Having support</strong> — <code>groupBy(SFunction...)</code> and <code>having(BiFunction)</code></li><li><strong>SubQuerySpec correlation</strong> — <code>correlate(root)</code> for subquery correlation</li><li><strong>Spring Boot auto-configuration</strong> — Auto-register <code>MyJpaTemplate</code> and components</li></ul><h2 id="_0-0-1-2026-05-26" tabindex="-1">[0.0.1] - 2026-05-26 <a class="header-anchor" href="#_0-0-1-2026-05-26" aria-label="Permalink to &quot;[0.0.1] - 2026-05-26&quot;">​</a></h2><h3 id="initial-release" tabindex="-1">Initial Release <a class="header-anchor" href="#initial-release" aria-label="Permalink to &quot;Initial Release&quot;">​</a></h3><ul><li>Lambda API based type-safe JPA <code>Specification</code> builder</li><li><code>QuerySpec&lt;T&gt;</code>: eq, ne, gt, ge, lt, le, like, notLike, in, notIn, between, isNull, isNotNull</li><li>JOIN support: <code>join()</code>, <code>leftJoin()</code> with <code>JoinGroup</code></li><li>OR groups: <code>or()</code> with <code>OrGroup</code></li><li>EXISTS subqueries with <code>SubQuerySpec</code></li><li>Multi-field LIKE search via <code>multiLike</code></li><li>Jackson serializer for Hibernate lazy proxies</li></ul>',36)])])}const h=o(r,[["render",l]]);export{p as __pageData,h as default};
